INSERT INTO reviewer_checklist (id, item_code, evidence_item, control_id, control_name, mandatory_advisory, l1_check, l2_check, l3_check) VALUES ('f0a9523f-d429-4815-9ba8-cfbe19a048fc'::uuid, 'A1', 'Network architecture diagram', '1.1', 'SWIFT Environment Protection', 'M', '{"task": "Submission Validation", "document": "Network architecture diagram", "checks": [{"id": 1, "check": "File Presence", "description": "File is present and can be opened"}, {"id": 2, "check": "Document Type", "description": "It is the correct document type (Diagram + Text)"}, {"id": 3, "check": "Section Completeness", "description": "All sections/fields are populated — no blanks for this Mandatory control"}, {"id": 4, "check": "Date Validity", "description": "Document is dated within the current assessment window"}, {"id": 5, "check": "Control Linkage", "description": "It is linked/tagged to Control SWIFT Environment Protection"}]}'::jsonb, '{"task": "Technical Review", "document": "Network architecture diagram", "control": "SWIFT Environment Protection", "must_show": ["Secure zone boundary clearly drawn with logical and physical separation indicated", "Stateful firewall devices shown at every ingress/egress point of the secure zone", "All SWIFT systems within secure zone visible: messaging interface, communication interface, GUI, SwiftNet Link, HSM, connectors, jump server", "Dedicated operator PCs shown inside zone; general-purpose PCs shown outside zone", "Jump server placement visible — inside secure zone or equivalent secure zone"], "pass_criteria": ["Zone boundary is explicitly drawn with firewall at every entry/exit point", "All 7+ SWIFT component types visible inside zone (messaging, comm, GUI, SNL, HSM, connector, jump server)", "Operator PC classification visible (dedicated inside, general-purpose outside)", "Jump server positioned inside zone or equivalent secure zone"], "fail_criteria": ["No clear zone boundary drawn", "SWIFT components shown outside secure zone without justification", "Enterprise AD shown as shared authentication crossing zone boundary without separate auth"], "cross_checks": ["Every system on diagram must appear in A2 inventory", "Every firewall on diagram must have corresponding A4 rule set"]}'::jsonb, '{"task": "Independent Attestation", "document": "Network architecture diagram", "control": "SWIFT Environment Protection", "mandatory": true, "gaps_permitted": false, "note": "Do not rely on L2 outcome — independently verify all items", "independent_verify": ["Zone boundary is explicitly drawn with firewall at every entry/exit point", "All 7+ SWIFT component types visible inside zone (messaging, comm, GUI, SNL, HSM, connector, jump server)", "Operator PC classification visible (dedicated inside, general-purpose outside)", "Jump server positioned inside zone or equivalent secure zone"], "cross_check_validation": ["Every system on diagram must appear in A2 inventory", "Every firewall on diagram must have corresponding A4 rule set"], "authenticity_check": "Is evidence authentic (not paper compliance)?", "dispute_action": "Raise formal comment if L2 Sufficient rating is disputed", "rating_options": ["Compliant", "Partially Compliant", "Non-Compliant", "N/A"], "rating": null}'::jsonb);
INSERT INTO reviewer_checklist (id, item_code, evidence_item, control_id, control_name, mandatory_advisory, l1_check, l2_check, l3_check) VALUES ('190b3a61-0812-4fcd-ba89-3fe0689f1afb'::uuid, 'A1', 'Network architecture diagram', '1.4', 'Restriction of Internet Access', 'M', '{"task": "Submission Validation", "document": "Network architecture diagram", "checks": [{"id": 1, "check": "File Presence", "description": "File is present and can be opened"}, {"id": 2, "check": "Document Type", "description": "It is the correct document type (Diagram + Text)"}, {"id": 3, "check": "Section Completeness", "description": "All sections/fields are populated — no blanks for this Mandatory control"}, {"id": 4, "check": "Date Validity", "description": "Document is dated within the current assessment window"}, {"id": 5, "check": "Control Linkage", "description": "It is linked/tagged to Control Restriction of Internet Access"}]}'::jsonb, '{"task": "Technical Review", "document": "Network architecture diagram", "control": "Restriction of Internet Access", "must_show": ["No direct internet connectivity path from any system inside the secure zone", "No direct internet connectivity from the jump server", "Proxy/gateway placement shown if indirect internet access exists for allowlisted URLs", "General-purpose operator PC internet access path visible — through remote desktop, proxy with content inspection, or web gateway", "Internet access from dedicated operator PCs blocked or highly restricted (shown)"], "pass_criteria": ["No uncontrolled internet path from secure zone systems", "Jump server explicitly shown with no internet access", "Proxy/gateway architecture visible for any permitted access"], "fail_criteria": ["Direct internet line from secure zone components", "Jump server shown with internet connectivity", "No indication of internet access control for operator PCs"], "cross_checks": ["Firewall rules in A4 must confirm deny-outbound for internet from zone"]}'::jsonb, '{"task": "Independent Attestation", "document": "Network architecture diagram", "control": "Restriction of Internet Access", "mandatory": true, "gaps_permitted": false, "note": "Do not rely on L2 outcome — independently verify all items", "independent_verify": ["No uncontrolled internet path from secure zone systems", "Jump server explicitly shown with no internet access", "Proxy/gateway architecture visible for any permitted access"], "cross_check_validation": ["Firewall rules in A4 must confirm deny-outbound for internet from zone"], "authenticity_check": "Is evidence authentic (not paper compliance)?", "dispute_action": "Raise formal comment if L2 Sufficient rating is disputed", "rating_options": ["Compliant", "Partially Compliant", "Non-Compliant", "N/A"], "rating": null}'::jsonb);
