INSERT INTO reviewer_checklist (id, item_code, evidence_item, control_id, control_name, mandatory_advisory, l1_check, l2_check, l3_check) VALUES ('bc79e500-5dbd-4501-b718-ad5ceb78cebf'::uuid, 'A3', 'Data flow diagrams', '2.4A', 'Back Office Data Flow Security', 'A', '{"task": "Submission Validation", "document": "Data flow diagrams", "checks": [{"id": 1, "check": "File Presence", "description": "File is present and can be opened"}, {"id": 2, "check": "Document Type", "description": "It is the correct document type (Diagram)"}, {"id": 3, "check": "Section Completeness", "description": "All sections/fields are populated — no blanks for this Advisory control"}, {"id": 4, "check": "Date Validity", "description": "Document is dated within the current assessment window"}, {"id": 5, "check": "Control Linkage", "description": "It is linked/tagged to Control Back Office Data Flow Security"}]}'::jsonb, '{"task": "Technical Review", "document": "Data flow diagrams", "control": "Back Office Data Flow Security", "must_show": ["Detailed back-office to secure zone flows showing: source back-office system, destination SWIFT component, bridging servers in path", "Each flow classified: direct (point-to-point) vs indirect (through bridging servers)", "Security method per leg/segment documented: end-to-end protection (LAU, XML DSIG, AES-GCM) OR per-leg TLS", "New flows (post-2025) vs legacy flows distinguished", "Flows to/from HSM separately shown"], "pass_criteria": ["All back-office flows mapped with complete path", "Direct vs indirect classification present", "Security method documented per flow/segment"], "fail_criteria": ["Flows without security method annotation", "Bridging servers in path not identified"], "cross_checks": ["Bridging servers match A2 inventory; encryption config in B3"]}'::jsonb, '{"task": "Independent Attestation", "document": "Data flow diagrams", "control": "Back Office Data Flow Security", "mandatory": false, "gaps_permitted": true, "note": "Do not rely on L2 outcome — independently verify all items", "independent_verify": ["All back-office flows mapped with complete path", "Direct vs indirect classification present", "Security method documented per flow/segment"], "cross_check_validation": ["Bridging servers match A2 inventory; encryption config in B3"], "authenticity_check": "Is evidence authentic (not paper compliance)?", "dispute_action": "Raise formal comment if L2 Sufficient rating is disputed", "rating_options": ["Compliant", "Partially Compliant", "Non-Compliant", "N/A"], "rating": null}'::jsonb);
