INSERT INTO reviewer_checklist (id, item_code, evidence_item, control_id, control_name, mandatory_advisory, l1_check, l2_check, l3_check) VALUES ('1d49b215-51e4-4209-9b62-bc675ee65f86'::uuid, 'A4', 'Firewall rule sets', '1.1', 'SWIFT Environment Protection', 'M', '{"task": "Submission Validation", "document": "Firewall rule sets", "checks": [{"id": 1, "check": "File Presence", "description": "File is present and can be opened"}, {"id": 2, "check": "Document Type", "description": "It is the correct document type (Config Export)"}, {"id": 3, "check": "Section Completeness", "description": "All sections/fields are populated — no blanks for this Mandatory control"}, {"id": 4, "check": "Date Validity", "description": "Document is dated within the current assessment window"}, {"id": 5, "check": "Control Linkage", "description": "It is linked/tagged to Control SWIFT Environment Protection"}]}'::jsonb, '{"task": "Technical Review", "document": "Firewall rule sets", "control": "SWIFT Environment Protection", "must_show": ["Rule sets from EVERY firewall at secure zone boundary exported", "Deny-by-default posture confirmed: explicit default-deny rule at end of each ruleset", "Only explicitly permitted traffic allowed (allowlisting approach) — no ''allow any'' rules", "Each rule has: source, destination, port, protocol, action, direction (inbound/outbound)", "Rules categorised: back-office connectivity, MV-SIPN/internet, operator PC to jump server, admin/backup outbound"], "pass_criteria": ["Default-deny at end of every ruleset", "No ''allow any'' rules present", "Every rule has source/dest/port/protocol/action", "Annual review evidence with sign-off date within 12 months"], "fail_criteria": ["''Allow any'' rules found in ruleset", "No default-deny posture", "Rules permitting direct internet from zone components"], "cross_checks": ["Firewalls match placement on A1 diagram"]}'::jsonb, '{"task": "Independent Attestation", "document": "Firewall rule sets", "control": "SWIFT Environment Protection", "mandatory": true, "gaps_permitted": false, "note": "Do not rely on L2 outcome — independently verify all items", "independent_verify": ["Default-deny at end of every ruleset", "No ''allow any'' rules present", "Every rule has source/dest/port/protocol/action", "Annual review evidence with sign-off date within 12 months"], "cross_check_validation": ["Firewalls match placement on A1 diagram"], "authenticity_check": "Is evidence authentic (not paper compliance)?", "dispute_action": "Raise formal comment if L2 Sufficient rating is disputed", "rating_options": ["Compliant", "Partially Compliant", "Non-Compliant", "N/A"], "rating": null}'::jsonb);
