rue, "gaps_permitted": false, "note": "Do not rely on L2 outcome — independently verify all items", "independent_verify": ["TLS 1.2+ enforced for all operator sessions", "Strong cipher suites only (AES-256, ECDHE)", "Session timeout configured", "Weak protocols disabled"], "cross_check_validation": ["Aligns with B3 transport-level encryption config"], "authenticity_check": "Is evidence authentic (not paper compliance)?", "dispute_action": "Raise formal comment if L2 Sufficient rating is disputed", "rating_options": ["Compliant", "Partially Compliant", "Non-Compliant", "N/A"], "rating": null}'::jsonb);
